export default "export function urlToCheckboxMatrix(\r\n  url: string,\r\n  size?: { width: number; height: number },\r\n  threshold: number = 128,\r\n): Promise<number[][]> {\r\n  return new Promise((resolve, reject) => {\r\n    const img = new Image();\r\n\r\n    // ⚠️ Important for cross-origin images\r\n    img.crossOrigin = 'anonymous';\r\n\r\n    img.onload = () => {\r\n      const canvas = document.createElement('canvas');\r\n      const ctx = canvas.getContext('2d');\r\n\r\n      if (!ctx) {\r\n        reject('Canvas not supported');\r\n        return;\r\n      }\r\n\r\n      const width = size?.width || img.width;\r\n      const height = size?.height || img.height;\r\n\r\n      canvas.width = width;\r\n      canvas.height = height;\r\n\r\n      // Draw image (resize if needed)\r\n      ctx.drawImage(img, 0, 0, width, height);\r\n\r\n      const { data } = ctx.getImageData(0, 0, width, height);\r\n\r\n      const result: number[][] = [];\r\n\r\n      for (let y = 0; y < height; y++) {\r\n        const row: number[] = [];\r\n\r\n        for (let x = 0; x < width; x++) {\r\n          const i = (y * width + x) * 4;\r\n\r\n          const r = data[i];\r\n          const g = data[i + 1];\r\n          const b = data[i + 2];\r\n\r\n          // Convert to grayscale\r\n          const gray = 0.299 * r + 0.587 * g + 0.114 * b;\r\n\r\n          // Threshold to 1 or 0\r\n          row.push(gray < threshold ? 1 : 0);\r\n        }\r\n\r\n        result.push(row);\r\n      }\r\n\r\n      resolve(result);\r\n    };\r\n\r\n    img.onerror = () => reject('Failed to load image');\r\n\r\n    img.src = url;\r\n  });\r\n}\r\n\r\nexport interface ImageMatrix {\r\n  matrix: number[][];\r\n  columns: number;\r\n  rows: number;\r\n}\r\n\r\nexport async function loadImageAsMatrix(\r\n  file: File,\r\n  maxSize: number = 60,\r\n  threshold: number = 128,\r\n): Promise<ImageMatrix> {\r\n  return new Promise((resolve, reject) => {\r\n    const img = new Image();\r\n\r\n    img.onload = () => {\r\n      const aspectRatio = img.width / img.height;\r\n\r\n      let columns: number;\r\n      let rows: number;\r\n\r\n      if (aspectRatio >= 1) {\r\n        columns = maxSize;\r\n        rows = Math.round(maxSize / aspectRatio);\r\n      } else {\r\n        columns = Math.round(maxSize * aspectRatio);\r\n        rows = maxSize;\r\n      }\r\n\r\n      const canvas = document.createElement('canvas');\r\n      const ctx = canvas.getContext('2d');\r\n\r\n      if (!ctx) {\r\n        reject('Canvas not supported');\r\n        return;\r\n      }\r\n\r\n      canvas.width = columns;\r\n      canvas.height = rows;\r\n\r\n      ctx.fillStyle = '#ffffff';\r\n      ctx.fillRect(0, 0, columns, rows);\r\n\r\n      const scale = Math.min(columns / img.width, rows / img.height);\r\n      const scaledWidth = img.width * scale;\r\n      const scaledHeight = img.height * scale;\r\n      const offsetX = (columns - scaledWidth) / 2;\r\n      const offsetY = (rows - scaledHeight) / 2;\r\n\r\n      ctx.drawImage(img, offsetX, offsetY, scaledWidth, scaledHeight);\r\n\r\n      const { data } = ctx.getImageData(0, 0, columns, rows);\r\n\r\n      const matrix: number[][] = [];\r\n\r\n      for (let y = 0; y < rows; y++) {\r\n        const row: number[] = [];\r\n        for (let x = 0; x < columns; x++) {\r\n          const i = (y * columns + x) * 4;\r\n          const gray = 0.299 * data[i] + 0.587 * data[i + 1] + 0.114 * data[i + 2];\r\n          row.push(gray < threshold ? 1 : 0);\r\n        }\r\n        matrix.push(row);\r\n      }\r\n\r\n      resolve({ matrix, columns, rows });\r\n    };\r\n\r\n    img.onerror = () => reject('Failed to load image');\r\n    img.src = URL.createObjectURL(file);\r\n  });\r\n}\r\n"